import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/modules/base_classes/attractor_module_base.dart';

/// Shared behavior contract for generated strange-attractor module smoke tests.
///
/// The contract intentionally stays at the public [AttractorModule] boundary: it
/// verifies module identity, shader wiring, preset shape, and metadata identity
/// without knowing any concrete generated module family.
void attractorModuleSmokeTests(
  String moduleName,
  AttractorModule Function() createModule, {
  required String expectedId,
  required String expectedShader,
}) {
  test('$moduleName instantiates', () {
    final m = createModule();
    expect(m.id, expectedId);
    expect(m.shader, expectedShader);
  });

  test('$moduleName presets are well-formed', () {
    final m = createModule();
    expect(m.presets, isNotEmpty);
    for (final p in m.presets) {
      final preset = p as dynamic;
      expect(preset.id, isNotEmpty);
      expect(preset.name, isNotEmpty);
    }
  });

  test('$moduleName metadata is consistent', () {
    final m = createModule();
    final metadata = m.metadata as dynamic;
    expect(metadata.id, m.id);
  });
}

